// FORMAT FINAL MESSAGE — PRODUCTION
// No mock/fallback results. No share footer. No name.

const SUPABASE_URL = 'https://zfyyiewkkjyzxnyiabvk.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InpmeXlpZXdra2p5enhueWlhYnZrIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzUwMzgwNjIsImV4cCI6MjA5MDYxNDA2Mn0.IKHgWH67KzKzLw7lgZHDTLi0UUgmAoyheSNr3O01EVU';

const item = $input.first().json;

const score = item.finalScore;
const percentile = item.percentile;
const percentileLabel = item.percentileLabel;
const rank = item.rank;
const total = item.totalCandidates;
const probability = item.probability;
const targetRole = item.targetRole;
const ai = item.ai_analysis;

// Score bar
const filled = Math.round(score / 10);
const empty = 10 - filled;
const scoreBar = '█'.repeat(filled) + '░'.repeat(empty);

// Rejection reasons — real AI output only, no fallback
let rejectionBlock = '';
ai.rejection_reasons.slice(0, 3).forEach((r, i) => {
  rejectionBlock += `${i + 1}. ${r.reason}\n`;
});

// Fixes — real AI output only, no fallback
let fixesBlock = '';
ai.fixes.slice(0, 3).forEach((f, i) => {
  fixesBlock += `${i + 1}. ${f.fix}\n`;
});

const oneLiner = ai.one_liner;

const message = `*CAREER RANK REPORT*
━━━━━━━━━━━━━━━━━━

🎯 Role: *${targetRole}*

📊 *Your Score: ${score}/100*
${scoreBar}

📈 Percentile: ${percentileLabel} *${percentile}*
🏅 Rank: *#${rank}* out of ${total}+ candidates
⚡ Interview Probability: *${probability}*

━━━━━━━━━━━━━━━━━━
❌ *WHY YOU'RE GETTING REJECTED:*

${rejectionBlock}
💡 _${oneLiner}_

━━━━━━━━━━━━━━━━━━
✅ *WHAT TO FIX:*

${fixesBlock}
━━━━━━━━━━━━━━━━━━
🚀 *Want to improve your rank?*

Get personalized job recommendations 👇
🔗 https://meracareer.io`;

// Reset session to IDLE — preserve name, email, linkedin, resume
try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${SUPABASE_URL}/rest/v1/whatsapp_sessions?phone=eq.${encodeURIComponent(item.from)}`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: {
      state: 'IDLE',
      updated_at: new Date().toISOString()
    },
    json: true
